var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"20년 전, 가변 심도 강습 작전 <color=#ffd34c>트러블 슈팅</color>","JPN":"20年前、可変深度強襲作戦<color=#ffd34c>トラブルシューティング</color>","ENG":"20 years ago, Variable Depth Assault Operation <color=#ffd34c>Troubleshooting</color>","TWN":"20年前，可變深度強襲作戰<color=#ffd34c>故障排除</color>","SCN":"20年前，可变深度强袭作战<color=#ffd34c>故障排除</color>","DEU":"20 years ago, Variable Depth Assault Operation <color=#ffd34c>Troubleshooting</color>","FRA":"20 years ago, Variable Depth Assault Operation <color=#ffd34c>Troubleshooting</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"최종국면, <color=#ffd34c>시무르그 요격전</color>","JPN":"最終局面、<color=#ffd34c>シムルグ迎撃戦</color>","ENG":"Final Phase, <color=#ffd34c>Simurgh Interception</color>","TWN":"決戰時刻，<color=#ffd34c>西摩格攔截戰</color>","SCN":"决战时刻，<color=#ffd34c>西摩格拦截战</color>","DEU":"Final Phase, <color=#ffd34c>Simurgh Interception</color>","FRA":"Final Phase, <color=#ffd34c>Simurgh Interception</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"웃기지 마……!! 그딴 게 최선이라고……!?","JPN":"ふざけるな……！！　それが最善だって……！？","ENG":"Don't make me laugh...! That's the best choice...?!","TWN":"開什麼玩笑……！！這就是最好的了……？！"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그건 그냥 도망친 것뿐이잖아……!!","JPN":"それはただ逃げただけじゃないか……！！","ENG":"That's just running away...!!","TWN":"這不就是逃跑嗎……！！"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나에게 있어서 최선이라는 건……!!","JPN":"アタシにとって最善ってのは……！！","ENG":"The best choice for me is...!","TWN":"對我來說最好的選擇是……！！"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"고민하고, 결심하고, 상처입고, 극복하고, 다짐하고, 좌절하고, 다시 일어서고……!","JPN":"悩んで、決意して、傷ついて、乗り越えて、誓って、挫折して、また立ち上がって……！","ENG":"After thinking, deciding, getting hurt, overcoming, promising, being discouraged, and getting back up...!","TWN":"我思考過、決定過、受傷過、克服過、承諾過、沮喪過，也重新站起來過……！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"최후의 최후까지 할 수 있는 건 전부 다 해본 뒤에 내리는 마지막 선택이야!","JPN":"最後の最後まで、ギリギリまでやれることを全部やってから決めることだ！","ENG":"After doing everything that I could until the very end, this is the choice I made!","TWN":"這是我拼盡全力直到最後才做出的選擇！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 끝에 어떤 결말이 기다리고 있다고 해도……!!","JPN":"その先にどんな結末が待っていようとも……！！","ENG":"It doesn't matter what's waiting for me at the other end...!","TWN":"不管最後等待我的結局是什麼……！！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"결코 후회가 남지 않도록!!","JPN":"決して後悔が残らないように！！","ENG":"I won't have any regrets!!","TWN":"我絕不再留下任何遺憾！！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"부정. 연합 역시 멸망을 피하기 위해, 동원할 수 있는 모든 연산을 동원했습니다.","JPN":"否定。連合もまた滅亡を避けるために、できる限りの演算を算出しました。","ENG":"Negative. The Interstellar Alliance had also run every possible calculation to avoid devastation.","TWN":"否定。為了避免滅亡，聯盟也動用了一切可以動用的資源。"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"아시모프께서는 유기체가 감당할 수 없는 긴 세월 동안, 그 문제만을 연산하셨습니다.","JPN":"アシモフは有機体が耐えられないほど長い期間、その問題の演算を繰り返しておられました。","ENG":"Asimov had calculated this problem for a time longer than an organism can handle.","TWN":"阿西莫夫在這個問題上花費了相當長的時間，比生物體能夠處理的時間還要長。"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"재차 부정. 엄정하신 기계 장치의 신께서 내린 결론을 부정할 셈입니까?","JPN":"再度否定。厳正なる機械装置の神が下した結論を否定するつもりですか？","ENG":"Double negative. Are you denying the conclusion made by the impartial God of Machinery?","TWN":"再次否認。你要否認公正的機械之神得出的結論嗎？"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그딴 거 내 알 바 아니야!","JPN":"そんなの、アタシの知ったことじゃない。","ENG":"I don't care about that!","TWN":"那不關我的事！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"세계가 어쩌고, 멸망이 어쩌고, 신이 어쩌고 그딴 와닿지도 않는 이야기! 알 바 아니라고!","JPN":"世界がどうの、滅亡がどうの、神がどうの。そんな話、知ったことじゃないんだよ！","ENG":"All this mumbo-jumbo about the world ending and whatever gods! That's none of my business!","TWN":"世界也好，毀滅也好，還有你們的神也好，這些虛無縹緲的事情！和我有什麼關係！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나는 그저 내 앞에서 누군가가 죽지 않길 바랄 뿐이야!","JPN":"アタシはただアタシの目の前で誰かが死ぬところを見たくないだけだ！","ENG":"All I want is for no one to die on my watch!","TWN":"我只希望沒有人死在我面前！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"너희들이 시험이라는 이유로 죽이려고 했던, 내 소중한 전대원들을 구하고 싶을 뿐이라고!!","JPN":"おまえらが試験という名目で殺そうとした、アタシの大切な戦隊員たちを助けたいだけなんだ！！","ENG":"I just want to save my precious division members that you're trying to kill for your stupid test!","TWN":"我只是想拯救我那些你們以測試為名而試圖殺死的戰隊成員！！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"크윽……!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳……！！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"엘부르즈 대검 파손. 물질 재구성까지 36초","JPN":"アルボルズ大剣破損。物質再構成まであと36秒。","ENG":"Alborz greatsword destroyed. Thirty-six seconds until material reconstruction.","TWN":"艾爾布勒茲損壞。距材料重構還需36秒。"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"시무르그 이민선 본체, 대기권 돌입. 대기와의 마찰열로 인해 표면 온도 급상승.","JPN":"シムルグ移民船本体、大気圏突入。大気との摩擦熱により、表面温度急上昇。","ENG":"Simurgh Exodus Fleet, entering the atmosphere. Temperature rapidly rising due to friction heat.","TWN":"西摩格移民船本體進入大氣層。由於與大氣的摩擦，表面溫度迅速升高。"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"경고. 이대로라면 당신도 무사하지 못할 겁니다.","JPN":"警告。このままだと、あなたも無事ではいられません。","ENG":"Warning. You will also not escape unharmed if this continues.","TWN":"警告。再繼續下去，你不可能活著離開這裡。"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"크윽!! 상관없어!!","JPN":"くうっ！！　構わない！！","ENG":"Khhkkk!! I don't care!!","TWN":"呃！！我才不管！！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 어떤 화염도 나를 막을 수는 없으니까!!","JPN":"どんな火炎であろうと、アタシを止めることはできない！！","ENG":"No flame can stop me!!","TWN":"任何火焰也阻擋不了我！！"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};